import Notification from "../models/Notification.js";

/**
 * Auto-Notification Engine
 * Creates Notification record in DB + emits socket event.
 * All auto-generated notifications are marked with isAutoGenerated: true.
 *
 * @param {Object} io         - Socket.io server instance
 * @param {Object} options
 * @param {string} options.title       - Notification title
 * @param {string} options.message     - Notification body
 * @param {string} [options.type]      - 'alert' | 'broadcast' | 'warning' | 'info'
 * @param {string} [options.severity]  - 'low' | 'medium' | 'high' | 'critical'
 * @param {string} [options.userId]    - Target user ID (for personal notifications)
 * @param {string[]} [options.targetAreas] - Areas affected
 * @param {string[]} [options.rooms]   - Additional socket rooms to emit to
 */
export const emitAutoNotification = async (io, {
  title,
  message,
  type = "info",
  severity = "medium",
  userId = null,
  targetAreas = [],
  rooms = [],
}) => {
  try {
    // 1. Save to DB
    const notification = new Notification({
      title,
      message,
      type,
      severity,
      targetAreas,
      isAutoGenerated: true,
      sentBy: { name: "System (Auto)" },
      targetUserId: userId || null,
    });
    await notification.save();

    // 2. Emit socket events
    if (io) {
      const payload = {
        _id: notification._id,
        title,
        message,
        type,
        severity,
        isAutoGenerated: true,
        createdAt: notification.createdAt,
      };

      // Always notify admin room
      io.to("admin_room").emit("notification_created", payload);

      // Notify specific user if userId provided
      if (userId) {
        io.to(`user_${userId}`).emit("notification_created", payload);
        io.to(`user_${userId}`).emit("user_notification", payload);
      }

      // Notify additional rooms
      rooms.forEach((room) => {
        io.to(room).emit("notification_created", payload);
      });
    }

    return notification;
  } catch (error) {
    console.error("[AUTO-NOTIFY] Failed to create notification:", error.message);
    return null;
  }
};

/**
 * Convenience: SOS received notification (to admins)
 */
export const notifySosReceived = (io, { userName, emergencyType, sosId }) =>
  emitAutoNotification(io, {
    title: `🚨 New SOS: ${emergencyType || "Emergency"}`,
    message: `SOS received from ${userName || "Unknown user"}. Emergency type: ${emergencyType || "unknown"}.`,
    type: "alert",
    severity: "high",
    rooms: ["volunteer_room"],
  });

/**
 * Convenience: Team dispatched notification (to user)
 */
export const notifyTeamDispatched = (io, { userId, teamName, eta, memberCount }) =>
  emitAutoNotification(io, {
    title: `🚑 Rescue Team Dispatched`,
    message: `Team "${teamName}" (${memberCount} members) has been dispatched to your location. ETA: ${eta || "calculating..."}.`,
    type: "info",
    severity: "medium",
    userId,
  });

