/**
 * Emergency Broadcast — used by riskEngine.js
 * Creates a critical broadcast notification and emits to all rooms.
 */
export const triggerEmergencyBroadcast = async (io, {
  title,
  message,
  severity = "critical",
  targetAreas = [],
  location = null,
}) => {
  return emitAutoNotification(io, {
    title: `⚠️ ${title}`,
    message,
    type: "broadcast",
    severity,
    targetAreas,
    rooms: ["volunteer_room"],
  });
};
